float kiln_profile_setpoint(unsigned long elapsed_s,const float* temps,const unsigned long* durations,int n_seg){
  unsigned long t=0;
  for(int i=0;i<n_seg-1;i++){
    unsigned long seg=durations[i];
    if(elapsed_s<t+seg){
      float frac=(float)(elapsed_s-t)/seg;
      return temps[i]+(temps[i+1]-temps[i])*frac;
    }
    t+=seg;
  }
  return temps[n_seg-1];
}
